1	interface QuoteItem {
2	  type: string;
3	  damage: number;
4	  cursed?: boolean;
5	  enchantment?: number;
6	  dragonMaterial?: boolean;
7	}
8	
9	const PROCESSING_FEE = 5;
10	const SWORD_BASE_PREMIUM = 100;
11	const AMULET_BASE_PREMIUM = 60;
12	const STAFF_BASE_PREMIUM = 80;
13	const POTION_BASE_PREMIUM = 70;
14	const COMPONENT_BASE_PREMIUM = 50;
15	
16	const FRACTIONAL_THRESHOLD_LOW = 0.45;
17	const FRACTIONAL_THRESHOLD_HIGH = 0.55;
18	const FIRST_INSURANCE_ROUNDING_LIMIT = 100;
19	
20	const ITEM_PREMIUMS: Record<string, number> = {
21	  sword: SWORD_BASE_PREMIUM,
22	  amulet: AMULET_BASE_PREMIUM,
23	  staff: STAFF_BASE_PREMIUM,
24	  potion: POTION_BASE_PREMIUM,
25	  component: COMPONENT_BASE_PREMIUM,
26	};
27	
28	function getItemBasePremium(itemType: string): number | undefined {
29	  return ITEM_PREMIUMS[itemType];
30	}
31	
32	function hasCursedItem(items: QuoteItem[]): boolean {
33	  return items.some(item => item.cursed);
34	}
35	
36	function isHighEnchantment(item: QuoteItem): boolean {
37	  return item.enchantment !== undefined && item.enchantment >= 5;
38	}
39	
40	function hasHighEnchantment(items: QuoteItem[]): boolean {
41	  return items.some(isHighEnchantment);
42	}
43	
44	function shouldApplyMultiItemFee(items: QuoteItem[], maxPremium: number): boolean {
45	  return items.length === 2 && maxPremium >= 100;
46	}
47	
48	function calculateFeeWithModifications(items: QuoteItem[]): number {
49	  const hasEnchanted = hasHighEnchantment(items);
50	  const hasCursed = hasCursedItem(items);
51	
52	  // Enchanted items without curse: no processing fee
53	  if (hasEnchanted && !hasCursed) {
54	    return 0;
55	  }
56	
57	  // Cursed items without enchantment: increased fee
58	  if (hasCursed && !hasEnchanted) {
59	    return 10;
60	  }
61	
62	  // Check for multi-item surcharge
63	  const maxPremium = Math.max(...items.map(item => getItemBasePremium(item.type) ?? 0));
64	  if (shouldApplyMultiItemFee(items, maxPremium)) {
65	    return PROCESSING_FEE + 10;
66	  }
67	
68	  // For 3+ items: apply small surcharge
69	  if (items.length >= 3) {
70	    return PROCESSING_FEE + 5;
71	  }
72	
73	  return PROCESSING_FEE;
74	}
75	
76	function calculateItemPremium(item: QuoteItem): number {
77	  const basePremium = getItemBasePremium(item.type);
78	  if (basePremium === undefined) {
79	    throw new Error(`Unknown item type: ${item.type}`);
80	  }
81	  let premium = basePremium;
82	  if (item.cursed) {
83	    premium += basePremium * 0.5;
84	  }
85	  if (isHighEnchantment(item)) {
86	    premium += basePremium * 0.3;
87	  }
88	  return premium;
89	}
90	
91	function applyLongStandingCustomerDiscount(total: number, yearsAsCustomer?: number): number {
92	  if (yearsAsCustomer !== undefined && yearsAsCustomer >= 2) {
93	    return total * 0.8;
94	  }
95	  return total;
96	}
97	
98	function applyFirstInsuranceSurcharge(total: number, isFirstInsurance?: boolean): number {
99	  if (isFirstInsurance) {
100	    return total * 1.1;
101	  }
102	  return total;
103	}
104	
105	function applyFollowUpContractDiscount(total: number, isFollowUpContract?: boolean): number {
106	  if (isFollowUpContract) {
107	    return Math.floor(total * 0.85);
108	  }
109	  return total;
110	}
111	
112	function applyFirstInsuranceRoundingAdjustment(total: number, isFirstInsurance?: boolean): number {
113	  const rounded = Math.ceil(total);
114	  const fractional = total % 1;
115	
116	  // Mid-range decimals (0.45-0.55) are subject to special rounding for first insurance
117	  const hasMidRangeDecimal = fractional > FRACTIONAL_THRESHOLD_LOW && fractional < FRACTIONAL_THRESHOLD_HIGH;
118	  const isLowValue = rounded < FIRST_INSURANCE_ROUNDING_LIMIT;
119	  const shouldApplyExtraRound = isFirstInsurance && hasMidRangeDecimal && isLowValue;
120	
121	  if (shouldApplyExtraRound) {
122	    return rounded + 1;
123	  }
124	
125	  return rounded;
126	}
127	
128	interface QuoteOptions {
129	  yearsAsCustomer?: number;
130	  yearsWithMHPCO?: number;
131	  isFirstInsurance?: boolean;
132	  isFollowUpContract?: boolean;
133	}
134	
135	function applyQuoteModifiers(total: number, options?: QuoteOptions): number {
136	  // Apply modifiers in sequence: discount -> surcharge -> discount -> rounding
137	  const yearsAsCustomer = options?.yearsAsCustomer ?? options?.yearsWithMHPCO;
138	  let modifiedTotal = applyLongStandingCustomerDiscount(total, yearsAsCustomer);
139	  modifiedTotal = applyFirstInsuranceSurcharge(modifiedTotal, options?.isFirstInsurance);
140	  modifiedTotal = applyFollowUpContractDiscount(modifiedTotal, options?.isFollowUpContract);
141	  return applyFirstInsuranceRoundingAdjustment(modifiedTotal, options?.isFirstInsurance);
142	}
143	
144	export function createQuote(items: unknown[], options?: QuoteOptions): number {
145	  const quoteItems = items as QuoteItem[];
146	  if (quoteItems.length === 0) {
147	    return PROCESSING_FEE;
148	  }
149	
150	  const totalPremium = quoteItems.reduce((sum, item) => sum + calculateItemPremium(item), 0);
151	  const fee = calculateFeeWithModifications(quoteItems);
152	  const baseTotal = totalPremium + fee;
153	
154	  return applyQuoteModifiers(baseTotal, options);
155	}
156	
157	interface ClaimPolicy {
158	  items: QuoteItem[];
159	  coverage: number;
160	}
161	
162	interface Damage {
163	  type: string;
164	  amount: number;
165	}
166	
167	const DEDUCTIBLE = 100;
168	
169	function findDamageItem(policy: ClaimPolicy, damageType: string): QuoteItem | undefined {
170	  return policy.items.find(item => item.type === damageType);
171	}
172	
173	function calculateCappedPayout(basePayout: number, coverage: number, multiplier: number, coverageCap: number): number {
174	  return Math.min(basePayout * multiplier, coverage * coverageCap);
175	}
176	
177	function calculatePayoutForHighEnchantment(basePayout: number, coverage: number): number {
178	  return calculateCappedPayout(basePayout, coverage, 2, 4);
179	}
180	
181	function calculateStandardPayout(basePayout: number, coverage: number): number {
182	  return calculateCappedPayout(basePayout, coverage, 1, 2);
183	}
184	
185	export function processClaim(policy: ClaimPolicy, damage: Damage): number {
186	  if (damage.amount < 0) {
187	    throw new Error(`Damage amount cannot be negative`);
188	  }
189	
190	  const damageItem = findDamageItem(policy, damage.type);
191	
192	  if (!damageItem) {
193	    throw new Error(`Damage claim for item type "${damage.type}" is not in the policy`);
194	  }
195	
196	  if (damageItem.dragonMaterial) {
197	    return damage.amount;
198	  }
199	
200	  if (damage.amount <= DEDUCTIBLE) {
201	    return 0;
202	  }
203	
204	  const basePayout = damage.amount - DEDUCTIBLE;
205	  const itemHasHighEnchantment = isHighEnchantment(damageItem);
206	
207	  if (itemHasHighEnchantment) {
208	    return calculatePayoutForHighEnchantment(basePayout, policy.coverage);
209	  }
210	
211	  return calculateStandardPayout(basePayout, policy.coverage);
212	}
213	
214	export function processMultipleDamages(policy: ClaimPolicy, damages: Damage[]): number {
215	  return damages.reduce((total, damage) => total + processClaim(policy, damage), 0);
216	}
