function shouldApplyMultiItemFee(items: QuoteItem[], maxPremium: number): boolean {
  return items.length === 2 && maxPremium >= 100;
}

function calculateProcessingFeeSurcharge(items: QuoteItem[]): number {
  const hasEnchanted = hasHighEnchantment(items);
  const hasCursed = hasCursedItem(items);

  // Enchanted items without curse: no processing fee
  if (hasEnchanted && !hasCursed) {
    return -PROCESSING_FEE; // Cancel the base fee
  }

  // Cursed items without enchantment: increased fee
  if (hasCursed && !hasEnchanted) {
    return 5; // 10 total = base 5 + surcharge 5
  }

  // Check for multi-item surcharge
  const maxPremium = Math.max(...items.map(item => getItemBasePremium(item.type) ?? 0));
  if (shouldApplyMultiItemFee(items, maxPremium)) {
    return 10; // Surcharge amount
  }

  // For 3+ items: apply small surcharge
  if (items.length >= 3) {
    return 5; // Surcharge amount
  }

  return 0; // No surcharge
}

function calculateProcessingFee(items: QuoteItem[]): number {
  return PROCESSING_FEE + calculateProcessingFeeSurcharge(items);
}
